import React, { useState, useEffect } from 'react';
import { useAuth } from '../../contexts/AuthContext';
import { userAPI } from '../../services/api';
import './Profile.css';

const Profile = () => {
  const [profile, setProfile] = useState({
    skills: [],
    interests: [],
    education: '',
    experience: 0,
    bio: ''
  });
  const [newSkill, setNewSkill] = useState('');
  const [newInterest, setNewInterest] = useState('');
  const [loading, setLoading] = useState(false);
  const [saving, setSaving] = useState(false);
  const [message, setMessage] = useState('');

  const { user, updateUser } = useAuth();

  useEffect(() => {
    fetchProfile();
  }, [user]);

  const fetchProfile = async () => {
    setLoading(true);
    try {
      // Get real user data from backend
      const userData = await userAPI.getProfile();
      console.log('📥 Profile data received:', userData);
      
      if (userData.success && userData.user) {
        setProfile({
          skills: userData.user.profile?.skills || [],
          interests: userData.user.profile?.interests || [],
          education: userData.user.profile?.education || '',
          experience: userData.user.profile?.experience || 0,
          bio: userData.user.profile?.bio || ''
        });
      }
      
    } catch (error) {
      console.error('Error fetching profile:', error);
      // Fallback to current user data
      if (user && user.profile) {
        setProfile({
          skills: user.profile.skills || [],
          interests: user.profile.interests || [],
          education: user.profile.education || '',
          experience: user.profile.experience || 0,
          bio: user.profile.bio || ''
        });
      }
    } finally {
      setLoading(false);
    }
  };

  const updateProfile = async (updates) => {
    setSaving(true);
    setMessage('');
    try {
      console.log('📤 Sending profile update:', updates);
      
      const response = await userAPI.updateProfile(updates);
      
      if (response.success) {
        setMessage('Profile updated successfully!');
        setProfile(updates);
        
        // Update the user in auth context
        if (updateUser) {
          updateUser(response.user);
        }
        
        setTimeout(() => setMessage(''), 3000);
      } else {
        setMessage('Error updating profile');
      }
    } catch (error) {
      setMessage('Failed to update profile');
      console.error('Profile update error:', error);
    } finally {
      setSaving(false);
    }
  };

  const handleSaveProfile = async (e) => {
    e.preventDefault();
    await updateProfile(profile);
  };

  const addSkill = () => {
    if (newSkill.trim() && !profile.skills.includes(newSkill.trim())) {
      const updatedSkills = [...profile.skills, newSkill.trim()];
      const updatedProfile = { ...profile, skills: updatedSkills };
      setProfile(updatedProfile);
      setNewSkill('');
      // Auto-save when adding skill
      updateProfile(updatedProfile);
    }
  };

  const removeSkill = (skillToRemove) => {
    const updatedSkills = profile.skills.filter(skill => skill !== skillToRemove);
    const updatedProfile = { ...profile, skills: updatedSkills };
    setProfile(updatedProfile);
    // Auto-save when removing skill
    updateProfile(updatedProfile);
  };

  const addInterest = () => {
    if (newInterest.trim() && !profile.interests.includes(newInterest.trim())) {
      const updatedInterests = [...profile.interests, newInterest.trim()];
      const updatedProfile = { ...profile, interests: updatedInterests };
      setProfile(updatedProfile);
      setNewInterest('');
      // Auto-save when adding interest
      updateProfile(updatedProfile);
    }
  };

  const removeInterest = (interestToRemove) => {
    const updatedInterests = profile.interests.filter(interest => interest !== interestToRemove);
    const updatedProfile = { ...profile, interests: updatedInterests };
    setProfile(updatedProfile);
    // Auto-save when removing interest
    updateProfile(updatedProfile);
  };

  const handleInputChange = (field, value) => {
    const updatedProfile = { ...profile, [field]: value };
    setProfile(updatedProfile);
  };

  if (!user) {
    return (
      <div className="profile-container">
        <div className="container">
          <div className="auth-required">
            <h2>Authentication Required</h2>
            <p>Please log in to view your profile.</p>
          </div>
        </div>
      </div>
    );
  }

  if (loading) {
    return (
      <div className="profile-container">
        <div className="container">
          <div className="loading">Loading profile...</div>
        </div>
      </div>
    );
  }

  return (
    <div className="profile-container">
      <div className="container">
        <div className="profile-header">
          <h1>Your Profile</h1>
          <p>Manage your personal information and career preferences</p>
        </div>

        {message && (
          <div className={`message ${message.includes('Error') ? 'error' : 'success'}`}>
            {message}
          </div>
        )}

        <form onSubmit={handleSaveProfile}>
          <div className="profile-content">
            {/* Personal Information */}
            <div className="profile-section">
              <h2>Personal Information</h2>
              <div className="profile-info">
                <div className="info-item">
                  <label>Full Name</label>
                  <p>{user.name}</p>
                </div>
                <div className="info-item">
                  <label>Email</label>
                  <p>{user.email}</p>
                </div>
                <div className="info-item">
                  <label>Member since</label>
                  <p>{new Date(user.createdAt).toLocaleDateString()}</p>
                </div>
              </div>
            </div>

            {/* Bio */}
            <div className="profile-section">
              <h2>Bio</h2>
              <textarea
                value={profile.bio}
                onChange={(e) => handleInputChange('bio', e.target.value)}
                placeholder="Tell us about yourself, your goals, and aspirations..."
                rows="4"
              />
            </div>

            {/* Education & Experience */}
            <div className="profile-grid">
              <div className="profile-section">
                <h2>Education</h2>
                <input
                  type="text"
                  value={profile.education}
                  onChange={(e) => handleInputChange('education', e.target.value)}
                  placeholder="Your educational background"
                />
              </div>

              <div className="profile-section">
                <h2>Experience (Years)</h2>
                <input
                  type="number"
                  value={profile.experience}
                  onChange={(e) => handleInputChange('experience', parseInt(e.target.value) || 0)}
                  min="0"
                  max="50"
                />
              </div>
            </div>

            {/* Skills */}
            <div className="profile-section">
              <h2>Skills</h2>
              <div className="tags-input">
                <div className="tags-list">
                  {profile.skills.map((skill, index) => (
                    <span key={index} className="tag">
                      {skill}
                      <button 
                        type="button"
                        onClick={() => removeSkill(skill)} 
                        className="remove-tag"
                      >
                        ×
                      </button>
                    </span>
                  ))}
                </div>
                <div className="input-group">
                  <input
                    type="text"
                    value={newSkill}
                    onChange={(e) => setNewSkill(e.target.value)}
                    onKeyPress={(e) => e.key === 'Enter' && (e.preventDefault(), addSkill())}
                    placeholder="Add a skill"
                  />
                  <button 
                    type="button"
                    onClick={addSkill} 
                    className="btn btn-primary"
                  >
                    Add
                  </button>
                </div>
              </div>
            </div>

            {/* Interests */}
            <div className="profile-section">
              <h2>Career Interests</h2>
              <div className="tags-input">
                <div className="tags-list">
                  {profile.interests.map((interest, index) => (
                    <span key={index} className="tag">
                      {interest}
                      <button 
                        type="button"
                        onClick={() => removeInterest(interest)} 
                        className="remove-tag"
                      >
                        ×
                      </button>
                    </span>
                  ))}
                </div>
                <div className="input-group">
                  <input
                    type="text"
                    value={newInterest}
                    onChange={(e) => setNewInterest(e.target.value)}
                    onKeyPress={(e) => e.key === 'Enter' && (e.preventDefault(), addInterest())}
                    placeholder="Add an interest"
                  />
                  <button 
                    type="button"
                    onClick={addInterest} 
                    className="btn btn-primary"
                  >
                    Add
                  </button>
                </div>
              </div>
            </div>

            {/* Save Button */}
            <div className="profile-actions">
              <button 
                type="submit"
                disabled={saving}
                className="btn btn-primary save-btn"
              >
                {saving ? 'Saving...' : 'Save Profile'}
              </button>
            </div>
          </div>
        </form>
      </div>
    </div>
  );
};

export default Profile;
